var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키, 왜 다들 우리를 노려보고 있는 거지?","JPN":"雅紀､どうしてみんな僕たちのことを睨んでるんだ?","ENG":"Masaki, why is everyone upset?","TWN":"雅紀，大家為什麼一直盯著我們？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래. 잘 돌아왔다고 환영해 주는 분위기는 아니군.","JPN":"さあな｡歓迎ムードじゃないことだけは確かだ｡","ENG":"Yeah, they don’t seem very welcoming.","TWN":"就是說，感覺也不是要歡迎我們的樣子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"평생 숨어 살아도 모자랄 것이 이런 상황에 뻔뻔스럽게 낯짝을 드러내다니.","JPN":"一族郎党まとめて罰せられてもおかしくないところを、よくものうのうと顔を出せたものだな。","ENG":"How dare you show your shameless face here.","TWN":"應該要一輩子躲起來贖罪的人，現在竟然有臉出現在我們面前！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"부끄러운 줄을 모르는구나, 하야미 사나에.","JPN":"恥を知れ、速水早苗。","ENG":"Have you completely lost your honor, Hayami Sanae?","TWN":"你真是不知羞恥，速水早苗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하야미?","JPN":"速水？","ENG":"Hayami?","TWN":"速水？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"설마…… 당신이 하야미 가문 사람이라고?","JPN":"まさか……速水家の人間なのか？","ENG":"You’re... from the Hayami family?","TWN":"難道…你是速水家族的人？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MEMBER_EXTRA_NANA_A","text":{"KOREA":"여기가 어디라고 돌아온 거냐!","JPN":"ここをどこだと思っている！","ENG":"Where do you think you are?","TWN":"你把這裡當成什麼地方了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MEMBER_EXTRA_NANA_A","text":{"KOREA":"이곳에 배신자 집안이 발을 들일 곳은 없다! 썩 꺼져!","JPN":"裏切者を受け入れるつもりはない！　さっさと失せろ！","ENG":"There is no place for a traitor here. Get out!","TWN":"這裡可不是叛徒該來的地方！給我滾出去！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자, 잠시만요.","JPN":"ちょ、ちょっと待ってください！","ENG":"H-hang on.","TWN":"等…等等。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭔가 오해가 있는 것 같은데요. 이 분은 저희가 무사히 돌아올 수 있게 도와준 분이에요.","JPN":"何か誤解してませんか。\\n彼女は僕たちが無事に戻れるように助けてくれた人です。","ENG":"There must be a misunderstanding. She helped us to come back.","TWN":"是不是有什麼誤會？多虧她出手相救我們才能夠平安回來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"바깥에서 흘러들어온 물고기들이 물을 흐리는구나.","JPN":"一匹の馬が狂えば千匹の馬も狂うとは、まさにこのことだ。","ENG":"You collateral families already have shown us enough disrespect.","TWN":"外來種入侵想搞破壞嗎！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"방계가 연합의 일에 참견하는 것도 모자라, 배신자까지 끌고 들어오다니.","JPN":"身の程知らずの傍系が連合のことに深入りするだけでは足りず、\\n裏切者まで引き入れるとは。","ENG":"And now you're bringing in the traitor as if it wasn’t enough.","TWN":"旁系自己插手聯盟的事還不夠，現在還要把叛徒扯進來嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키, 너도 같이 해명 좀 해 줘.","JPN":"雅紀、お前もなんとか言ってくれよ。","ENG":"Masaki, help me here.","TWN":"雅紀，你也快幫忙解釋一下。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미안하다, 미나토.","JPN":"すまない、湊。","ENG":"I’m sorry, Minato.","TWN":"抱歉，南裕夏。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"저 사람이 하야미 가문 출신이라면, 난 더 이상 개입하고 싶지 않아.","JPN":"あの人が速水家の出身ということが事実なら、\\nオレはこれ以上関わりたくない。","ENG":"If she’s from the Hayami family, I have no quarrel in this.","TWN":"如果她是速水家族的人，那我沒什麼好說的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"너도 그러는 편이 좋을 거고.","JPN":"お前もそうしたほうがいい。","ENG":"And I suggest you stay out, too.","TWN":"你也不要再替她說話比較好。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키……","JPN":"雅紀……","ENG":"Masaki...","TWN":"雅紀……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"선대 나나하라 당주도 없는 지금 연합에 널 반겨 줄 사람은 없다, 사나에.","JPN":"先代の七原家当主も亡き今、連合でお前を歓迎する者はおらん。","ENG":"The previous leader of the Nanahara family is gone, there’s no one to welcome you here, Sanae.","TWN":"先祖七原堂主已經不在了，現在聯盟中沒有人會歡迎你，早苗。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"무슨 꿍꿍이로 나타났는지는 몰라도, 얌전히 돌아가라.","JPN":"何を企んでいるか知らんが、大人しく帰れ。","ENG":"I don’t know what you’re scheming, but you’d better go back where you came from.","TWN":"我不清楚你在打什麼算盤，但我勸你還是乖乖回去吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MEMBER_EXTRA_NANA_A","text":{"KOREA":"지금 돌려보내는 것도 불안합니다! 무슨 짓을 저지를지도 모르잖습니까!","JPN":"このまま帰すのも不安です！　何をするかわかりませんよ！","ENG":"We can’t just let her go! We don’t know what she’s up to!","TWN":"現在讓她回去也不安全！誰知道她會做出什麼事來！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MEMBER_EXTRA_NANA_A","text":{"KOREA":"이 참에 가둬 둬야 후환이 없을 겁니다!","JPN":"後顧の憂いのないよう、拘束したほうがよいのでは？","ENG":"She has to be locked up!","TWN":"乾脆趁這個機會把她關起來杜絕後患！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"TWN":"　　"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"밖이 소란스러워서 나왔는데 그럴 만한 이유가 있었군요.","JPN":"騒々しいから何事かと思えば、これは騒ぎになる訳ですね。","ENG":"I wondered what the commotion was about, and now I see what’s happening.","TWN":"我還想說外面在吵什麼，原來是這樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 그렇지만 어떤 이유도 여럿이 한 사람을 비난할 명분은 되지 않습니다.","JPN":"ええ。ですが、どんな理由であれ多数が一人を非難する名分にはなりません。","ENG":"Yes, and I see no honor in a group of people criticizing one person.","TWN":"嗯，但無論如何，都不應該以多欺少。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠……?","JPN":"千夏……？","ENG":"Chinatsu?","TWN":"千夏……？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"장로님. 하야미 사나에의 처우는 제가 맡겠습니다.","JPN":"長老、速水早苗の処遇は私にお任せください。","ENG":"Elder, please let me decide what will become of Hayami Sanae.","TWN":"長老，速水早苗就交由我處理吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"크흠…….","JPN":"ふむ……","ENG":"Ahem...","TWN":"咳咳……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"뭐, 어디 뜻대로 해 보시지요. 나나하라 당주.","JPN":"それでは好きにしてくだされ、七原家当主よ。","ENG":"Well, do what you will, Lady Nanahara.","TWN":"嗯，那就照七原堂主的意思吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"하야미 가문의 하야미 사나에. 나나하라의 당주님을 뵙습니다.","JPN":"七原家のご当主様、早苗でございます。","ENG":"Hayami Sanae of the Hayami family greets you, Lady Nanahara.","TWN":"速水家族的速水早苗，見過七原堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……오랜만이네요. 그간 별탈없이 지내셨나요.","JPN":"……久しぶりですね。お変わりはありませんか。","ENG":"It’s been a while. How have you been?","TWN":"……好久不見，這段時間別來無恙嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지낼 곳을 마련해 주신 배려 덕에 탈은 없습니다.","JPN":"生活できる場所を用意してくださったおかげで、何の問題もございません。","ENG":"I’ve been doing well, thank you for the place you prepared for me.","TWN":"謝謝堂主為我安排的住處，一切都很好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지금은 그저 어미가 진 빚을 갚기 위해, 죽지 못해 살아갈 뿐이지요.","JPN":"今はただ、母の罪を償うため死ぬこともできず生きているだけでございます。","ENG":"I’m only living this miserable life to pay for the debt that my mother owed to you.","TWN":"現在還苟活著是因為要替家母還債。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"바람이 속삭여 주더군요. 그대가 위험에 빠진 미나토 님과 카토리 당주를 도와주셨다고요.","JPN":"風がささやいてくれました。湊様と香取家当主を助けてくださったそうですね。","ENG":"The wind told me that you saved Mr. Nayuka and Mr. Katori when they were in danger.","TWN":"風聲告訴我，說南裕夏和香取堂主落難時，是你出手相救的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"돌아오면 안 된다는 것은 알고 있었습니다.","JPN":"戻ってきてはいけないということは承知しておりました。","ENG":"I know I wasn’t supposed to come back.","TWN":"我知道我不該回來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께선 제가 연합에 있으면 내분과 불화의 씨앗이 될 것이라 하셨죠.","JPN":"ご当主様は私が連合にいれば、内紛と不和の種になるとおっしゃいました。","ENG":"Lady Nanahara told me that I’d be the seed of dispute if I stayed here.","TWN":"堂主說過，我待在聯盟的話，就會埋下內鬨的種子。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그 말씀은 아직도 유효한 것일까요?","JPN":"それは今もお変わりないでしょうか？","ENG":"Do you still believe so?","TWN":"這句話現在還是一樣嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네. 그래서 이곳을 떠나 몸을 숨기는 편이 좋을 것이라 말씀드렸죠.","JPN":"……はい。ですので、ここを離れて身を隠した方が良いと伝えたのです。","ENG":"... Yes. That’s why I told you to stay hidden, leaving this place behind.","TWN":"……沒錯，我說過離開這裡，隱姓埋名對大家都好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 이번엔 그대의 선택에 맡기겠습니다.","JPN":"ですが、今回はあなたに選択を委ねましょう。","ENG":"But this time, I’ll let you choose.","TWN":"不過這次我要把選擇權交給你。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 더 이상…… 누군가의 선택을 강요하지 않기로 했으니까요.","JPN":"私はこれ以上……誰かの選択を強要することはしないと決めました。","ENG":"Because... I decided that I won’t force my decisions on anyone anymore.","TWN":"因為我決定……不再強人所難。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그렇습니까. 못 뵌 사이 많이 변하셨군요.","JPN":"そうですか。しばらくお会いできない間に、ずいぶんとお変わりになられたのですね。","ENG":"I see. You have changed.","TWN":"是嗎？堂主這段時間改變不少呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……그대도 제가 그렇게 보이나요?","JPN":"……貴方にもそう見えますか？","ENG":"... I heard that before.","TWN":"……你也是那麼看我的嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주로서 한 사람 몫을 해내기 위해 노력했지만…… 결국 나약해지고 있는 거겠죠.","JPN":"当主としての役割を果たすため力を尽くしてきましたが……\\n結局のところ、臆病なだけなのでしょう。","ENG":"I’m doing my best to be a good leader for the family... but I suppose I’m just being weak.","TWN":"身為堂主，雖然已經盡我最大的努力……結果卻是越來越懦弱。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"정말로 그렇게 생각하시나요?","JPN":"そんなことはございません。","ENG":"Is that what you really think?","TWN":"堂主真那麼想嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"번데기를 당장은 나약하다고 말할 수 있으나, 그것은 변화의 과정일 뿐입니다.","JPN":"ご当主様もまだ道半ばなのでしょう。","ENG":"A pupa may be weak, but it’s a preparation for change.","TWN":"你可以說毛毛蟲很弱小，但那只不過是蛻變的過程。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"번데기?","JPN":"道半ば？","ENG":"A pupa?","TWN":"毛毛蟲？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"죄송합니다. 주제넘는 소릴 했군요.","JPN":"申し訳ございません。余計なことを口にしてしまいました。","ENG":"My apologies. I stepped out of line.","TWN":"抱歉，我失言了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"전 그저 당주님께서 잘못된 선택을 하고 계신 게 아니라는 말씀을 드리고 싶었습니다.","JPN":"私はただ、ご当主様の選択は間違っていないとお伝えしたかったのです。","ENG":"All I meant was that your decisions were not wrong.","TWN":"我只是想表達，做出錯誤選擇的不是堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"치후유.","JPN":"千冬様。","ENG":"Chifuyu.","TWN":"千冬。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아, 장로님.","JPN":"あ、長老。","ENG":"Elder.","TWN":"長老。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님께서는 지금 대화 중이십니다. 용무가 있다면 잠시 기다려주십시오.","JPN":"当主はただ今取り込み中です。用件があるようでしたら、しばらくお待ちいただけますか。","ENG":"Lady Nanahara is busy now. If you have business with her, please wait.","TWN":"堂主正在談話中，若有事要找堂主，請在此稍候一下。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"소식은 들었습니다. 하야미 사나에가 돌아왔다지요.","JPN":"話は聞きましたよ。速水早苗が帰ってきたそうですね。","ENG":"I heard the news. Hayami Sanae is back.","TWN":"我聽說了，速水早苗回來了對吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"연합을 배신한 가문의 딸이 아직도 목숨을 부지하고 있다니……. 유감스러운 일입니다.","JPN":"連合を裏切った家門の娘がまだ生きているなんて……残念なことです。","ENG":"The daughter of the family that betrayed the Alliance still lives... That is very regrettable.","TWN":"叛徒的女兒竟然還活著……真是令人遺憾。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"치후유는 저 여자에게 무술을 배웠죠? 이번 일에 대해 어찌 생각하나요?","JPN":"千冬様はあの女から武術を学びましたね？\\n今回の出来事についてどうお考えですか？","ENG":"I know that woman taught you how to fight. How do you feel?","TWN":"千冬跟那個女人學過武術吧？這件事你怎麼看？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"제 생각은 중요치 않습니다. 하야미 사나에의 처우는 당주님 소관입니다.","JPN":"私の考えは重要ではありません。\\n速水早苗の処遇は当主が決めることです。","ENG":"What I feel is not important. She will decide what will become of Hayami Sanae.","TWN":"我怎麼看不重要，堂主怎麼看才重要。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"어째서 이 시기에 모습을 내비쳤는지는 모르나, 당주는 아마도 사나에를 내쫓지 않으실 겁니다.","JPN":"どうしてこの時に現れたのかはわかりませんが、\\nご当主はきっと早苗を追い出さないでしょう。","ENG":"I don’t know why she came back now, but I don’t think Lady Nanahara will banish her.","TWN":"雖然不知道她爲何挑這個時間點出現，但堂主應該不會趕她走。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"돌아온 사람을 함부로 내칠 정도로 모진 분이 아니니까요.","JPN":"帰ってきた人を無下に追いだすような厳しいお方ではありませんから。","ENG":"She is not cruel enough to turn away the woman who came back.","TWN":"畢竟堂主沒有冷血到可以將回來的人趕走。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"연합은 분명 반발하겠지만, 나나하라 당주의 명을 거스를 순 없겠지요.","JPN":"連合はきっと反発すると思いますが、\\n七原家当主の命に逆らうことはできないでしょう。","ENG":"The Alliance won’t like it, but they can’t defy their leader.","TWN":"聯盟一定會有意見，但又不能違抗七原堂主的命令。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이번 일은, 치후유 공에게는 당주님을 지킬 좋은 명분으로 보이는군요.","JPN":"今回のことは千冬様にとって、ご当主を守る良い名分になりますね。","ENG":"Her decision will give you good cause to protect her, Sir Chifuyu.","TWN":"這次的事情可以成為你保護堂主的好藉口。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"명분이라니. 무슨 말씀을 하시는지 모르겠습니다만.","JPN":"名分とは。おっしゃる言葉の意味がわかりませんが。","ENG":"A cause? I don’t know what you’re talking about.","TWN":"什麼藉口，我聽不懂你在說什麼。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"늘 당주 곁을 지키는 그대라면 잘 알고 있지 않나요?","JPN":"ご当主を常に守っているそなたならおわかりでは？","ENG":"You’ve been watching her closely all these years, you should know.","TWN":"你一直待在堂主身邊，應該很清楚吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주께서는 변하셨습니다. 약해지셨지요.","JPN":"ご当主はお変わりになられました。弱っているようですね。","ENG":"Lady Nanahara has changed. She’s gone soft.","TWN":"堂主變了，她變弱了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주는 더 이상 연합원들을 사지로 내몰 수 있을 만큼 강한 분이 아닙니다.","JPN":"もはや連合員を死地に送れるほど\\n強い心をもったお方ではありません。","ENG":"She is no longer a person who can send the members into harm’s way.","TWN":"堂主已經不再強大到能將聯盟成員逼到絕境。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"분명 오로치의 봉인을 막기 위해, <color=#ffd34c>가장 적은 희생</color>을 치르는 방법을 택하실 겁니다.","JPN":"きっとオロチの封印を維持するために<color=#ffd34c>最も少ない犠牲</color>で済む方法を選ばれることでしょう。","ENG":"She will choose the way with the <color=#ffd34c>minimum sacrifice</color> when sealing Orochi again.","TWN":"爲了阻止大蛇的封印崩壞，她一定會選擇將<color=#ffd34c>犧牲降到最低</color>的方法。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당주의 호위무사인 그대라면, 잘 알고 있지 않나요?","JPN":"ご当主の護衛であるそなたなら、よくご存じでしょう。","ENG":"You are her bodyguard. You know what I mean.","TWN":"你身為堂主的護衛，應該很清楚吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"곧 의전을 다시 소집하도록 하겠습니다.","JPN":"近いうちに会合を開く予定です。","ENG":"I will call for another meeting soon.","TWN":"我很快就會再召聚大家。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"치후유 공은 그저 호위무사로서 본분을 다하십시오.","JPN":"千冬様は護衛としての本分を全うしてください。","ENG":"Sir Chifuyu, you do your job as a bodyguard.","TWN":"千冬你就盡你身為護衛武士本份吧。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"나머지는…… 이 늙은이에게 맡겨 두시면 됩니다.","JPN":"後は……この老いぼれにお任せを。","ENG":"And let this old woman take care of the rest.","TWN":"其餘的……就交給我這個老人家。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};